+                deinit(gen.target, allocator);
+                allocator.destroy(gen.target);
+                deinit(gen.iter, allocator);
+                allocator.destroy(gen.iter);
+                for (gen.ifs) |*f| deinit(f, allocator);
+                allocator.free(gen.ifs);
+            }
+            allocator.free(dc.generators);
+        },
+        .tuple => |t| {
