+                        deinit(l, allocator);
+                        allocator.destroy(l);
+                    }
+                    if (sl.upper) |u| {
+                        deinit(u, allocator);
+                        allocator.destroy(u);
+                    }
+                    if (sl.step) |st| {
+                        deinit(st, allocator);
+                        allocator.destroy(st);
+                    }
+                },
+            }
+        },
+        .attribute => |a| {
+            deinit(a.value, allocator);
+            allocator.destroy(a.value);
+        },
+        .expr_stmt => |e| {
+            deinit(e.value, allocator);
+            allocator.destroy(e.value);
+        },
+        .await_expr => |a| {
+            deinit(a.value, allocator);
+            allocator.destroy(a.value);
+        },
+        .import_stmt => |i| {
+            // Strings are owned by parser arena, no need to free
+            _ = i;
+        },
+        .import_from => |i| {
