+            return switch (sub.slice) {
+                .index => |idx| exprUsesSelf(idx.*),
+                .slice => |sl| {
+                    if (sl.lower) |l| if (exprUsesSelf(l.*)) return true;
+                    if (sl.upper) |u| if (exprUsesSelf(u.*)) return true;
+                    if (sl.step) |s| if (exprUsesSelf(s.*)) return true;
+                    return false;
+                },
+            };
+        },
+        else => false,
+    };
